CREATE DATABASE IF NOT EXISTS ez_wallet_secure CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE ez_wallet_secure;
DROP TABLE IF EXISTS audit_logs; DROP TABLE IF EXISTS password_resets; DROP TABLE IF EXISTS contact_messages; DROP TABLE IF EXISTS notifications; DROP TABLE IF EXISTS recharges; DROP TABLE IF EXISTS bill_payments; DROP TABLE IF EXISTS transactions; DROP TABLE IF EXISTS wallets; DROP TABLE IF EXISTS recharge_operators; DROP TABLE IF EXISTS bill_categories; DROP TABLE IF EXISTS users;
CREATE TABLE users (id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) NOT NULL,username VARCHAR(80) NOT NULL UNIQUE,email VARCHAR(150) NOT NULL UNIQUE,phone VARCHAR(30) NOT NULL,password_hash VARCHAR(255) NOT NULL,role ENUM('admin','user') NOT NULL DEFAULT 'user',status ENUM('active','inactive') NOT NULL DEFAULT 'active',avatar VARCHAR(255) NULL,created_at DATETIME NOT NULL,updated_at DATETIME NOT NULL) ENGINE=InnoDB;
CREATE TABLE wallets (id INT AUTO_INCREMENT PRIMARY KEY,user_id INT NOT NULL UNIQUE,balance DECIMAL(12,2) NOT NULL DEFAULT 0.00,created_at DATETIME NOT NULL,updated_at DATETIME NOT NULL,CONSTRAINT fk_wallet_user FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE bill_categories (id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) NOT NULL,code VARCHAR(50) NOT NULL UNIQUE,status ENUM('active','inactive') NOT NULL DEFAULT 'active',created_at DATETIME NOT NULL) ENGINE=InnoDB;
CREATE TABLE recharge_operators (id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) NOT NULL,code VARCHAR(50) NOT NULL UNIQUE,status ENUM('active','inactive') NOT NULL DEFAULT 'active',created_at DATETIME NOT NULL) ENGINE=InnoDB;
CREATE TABLE transactions (id INT AUTO_INCREMENT PRIMARY KEY,reference_no VARCHAR(60) NOT NULL,user_id INT NOT NULL,related_user_id INT NULL,type ENUM('topup','transfer','bill_payment','recharge') NOT NULL,direction ENUM('credit','debit') NOT NULL,amount DECIMAL(12,2) NOT NULL,fee DECIMAL(12,2) NOT NULL DEFAULT 0.00,description VARCHAR(255) NULL,status ENUM('pending','completed','failed') NOT NULL DEFAULT 'completed',created_at DATETIME NOT NULL,INDEX idx_transaction_user (user_id),INDEX idx_reference (reference_no),CONSTRAINT fk_transaction_user FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,CONSTRAINT fk_transaction_related_user FOREIGN KEY (related_user_id) REFERENCES users(id) ON DELETE SET NULL) ENGINE=InnoDB;
CREATE TABLE bill_payments (id INT AUTO_INCREMENT PRIMARY KEY,user_id INT NOT NULL,bill_category_id INT NOT NULL,account_number VARCHAR(80) NOT NULL,amount DECIMAL(12,2) NOT NULL,reference_no VARCHAR(60) NOT NULL,status ENUM('pending','completed','failed') NOT NULL DEFAULT 'completed',created_at DATETIME NOT NULL,CONSTRAINT fk_bill_user FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,CONSTRAINT fk_bill_category FOREIGN KEY (bill_category_id) REFERENCES bill_categories(id)) ENGINE=InnoDB;
CREATE TABLE recharges (id INT AUTO_INCREMENT PRIMARY KEY,user_id INT NOT NULL,operator_id INT NOT NULL,phone_number VARCHAR(30) NOT NULL,amount DECIMAL(12,2) NOT NULL,reference_no VARCHAR(60) NOT NULL,status ENUM('pending','completed','failed') NOT NULL DEFAULT 'completed',created_at DATETIME NOT NULL,CONSTRAINT fk_recharge_user FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,CONSTRAINT fk_recharge_operator FOREIGN KEY (operator_id) REFERENCES recharge_operators(id)) ENGINE=InnoDB;
CREATE TABLE notifications (id INT AUTO_INCREMENT PRIMARY KEY,user_id INT NOT NULL,title VARCHAR(150) NOT NULL,message TEXT NOT NULL,is_read TINYINT(1) NOT NULL DEFAULT 0,created_at DATETIME NOT NULL,INDEX idx_notification_user (user_id),CONSTRAINT fk_notification_user FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE contact_messages (id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) NOT NULL,email VARCHAR(150) NOT NULL,subject VARCHAR(150) NOT NULL,message TEXT NOT NULL,status ENUM('new','reviewed') NOT NULL DEFAULT 'new',created_at DATETIME NOT NULL) ENGINE=InnoDB;
CREATE TABLE password_resets (id INT AUTO_INCREMENT PRIMARY KEY,email VARCHAR(150) NOT NULL,token VARCHAR(100) NOT NULL,expires_at DATETIME NOT NULL,created_at DATETIME NOT NULL,used_at DATETIME NULL,INDEX idx_password_token (token)) ENGINE=InnoDB;
CREATE TABLE audit_logs (id INT AUTO_INCREMENT PRIMARY KEY,user_id INT NULL,action VARCHAR(100) NOT NULL,details VARCHAR(255) NOT NULL,created_at DATETIME NOT NULL,CONSTRAINT fk_audit_user FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE SET NULL) ENGINE=InnoDB;
